import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { searchWorkers, getRoom } from '../utils/api';
import useLocation from '../hooks/useLocation';

const WORK_TYPES = [
  'all', 'plumber', 'electrician', 'driver', 'helper', 'carpenter',
  'painter', 'cleaner', 'cook', 'security', 'gardener', 'other',
];

const Workers = () => {
  const [workers, setWorkers] = useState([]);
  const [workType, setWorkType] = useState('all');
  const [loading, setLoading] = useState(false);
  const { location } = useLocation();
  const navigate = useNavigate();

  const load = async () => {
    if (!location) return;
    setLoading(true);
    try {
      const params = { lat: location.lat, lng: location.lng, radius: 10 };
      if (workType !== 'all') params.workType = workType;

      const res = await searchWorkers(params);
      setWorkers(res.data);
    } catch (err) {
      console.log(err);
    }
    setLoading(false);
  };

  useEffect(() => {
    load();
  }, [location, workType]);

  const handleMessage = async (wId) => {
    try {
      const res = await getRoom(wId);
      navigate(`/chat/${res.data.roomId}/${wId}`);
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div className="page">

      {/* Header + Dropdown */}
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: 16
      }}>
        <div className="section-title">👷 Workers Nearby</div>

        <select
          className="form-select"
          style={{ maxWidth: 200 }}
          value={workType}
          onChange={(e) => setWorkType(e.target.value)}
        >
          {WORK_TYPES.map((w) => (
            <option key={w} value={w}>
              {w === 'all' ? 'All Workers' : w.charAt(0).toUpperCase() + w.slice(1)}
            </option>
          ))}
        </select>
      </div>

      {/* Loading */}
      {loading ? (
        <div className="loading">
          <div className="spinner" />
        </div>
      ) : workers.length === 0 ? (

        /* Empty */
        <div className="empty-state">
          <div className="empty-icon">🔍</div>
          <p>No workers found nearby</p>
        </div>

      ) : (

        /* Workers List */
        workers.map((w) => (
          <div
            key={w._id}
            className="card"
            style={{
              padding: 14,
              display: 'flex',
              gap: 12,
              alignItems: 'center'
            }}
          >

            {/* Avatar */}
            {w.profilePhoto ? (
              <img
                src={w.profilePhoto}
                alt={w.name}
                style={{
                  width: 60,
                  height: 60,
                  borderRadius: '50%',
                  objectFit: 'cover'
                }}
              />
            ) : (
              <div
                className="avatar-placeholder"
                style={{ width: 60, height: 60, fontSize: '1.3rem' }}
              >
                {w.name?.[0]?.toUpperCase()}
              </div>
            )}

            {/* Info */}
            <div
              onClick={() => navigate(`/profile/${w._id}`)}
              style={{ cursor: 'pointer', flex: 1 }}
            >
              <div style={{ fontWeight: 700, fontSize: '1rem' }}>
                {w.name}
              </div>

              <div
                className="profile-badge"
                style={{ display: 'inline-block', margin: '4px 0' }}
              >
                {w.workType}
              </div>

              <div
                style={{
                  display: 'flex',
                  gap: 12,
                  fontSize: '0.8rem',
                  color: 'var(--mid)'
                }}
              >
                <span>⭐ {w.rating?.toFixed(1) || 'New'}</span>
                <span>📍 {w.distance} km</span>
              </div>
            </div>

            {/* Chat Button */}
            <button
              className="btn btn-primary btn-sm"
              onClick={() => handleMessage(w._id)}
            >
              💬
            </button>

          </div>
        ))
      )}
    </div>
  );
};

export default Workers;
